const calculateQuotePremium = (items: any[]): number => {
  const componentCounts: Record<string, number> = {};
  let premium = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.includes(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      premium += basePremiumForType(item.type);
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === BLOCK_SIZE) {
      premium += BLOCK_PREMIUM;
    } else {
      premium += count * basePremiumForType(type);
    }
  }
  return premium + PROCESSING_FEE;
};
```
- Constants: 2 ({}, 0, 0, 1) -- actually: {}, 0, 0, 1 = 4 constants = 4
- Bindings: 6 (calculateQuotePremium, items, componentCounts, premium, item, type, count) = 7 bindings = 7
- Invocations: 5 (includes, basePremiumForType x2, Object.entries, +/operations don't count as invocations -- actually: COMPONENT_TYPES.includes, componentCounts[item.type] access, basePremiumForType twice, Object.entries) = 5 invocations = 10
- Conditionals: 2 (two if statements) = 8
- Loops: 2 (two for loops) = 10
- Assignments: 5 (componentCounts=, premium=0, componentCounts[item.type]=, premium+=, premium+=, premium+=) = let me be precise: `const componentCounts = {}` (1), `let premium = 0` (1), `componentCounts[item.type] = ...` (1), `premium += basePremiumForType(item.type)` (1), `premium += BLOCK_PREMIUM` (1), `premium += count * basePremiumForType(type)` (1) = 6 assignments = 36
